fn smoke_loop_diverge(samples: &Path, audit_root: &Path) -> Result<(), String> {
    let events = run_sample(
        samples.join("loop_no_converge.yaml"),
        audit_root,
        "loop-diverge",
        Value::Null,
        true,
        &[],
    )?;
    if find_event(&events, "loop.did_not_converge").is_none() {
        return Err("no loop.did_not_converge event".into());
    }
    Ok(())

pub enum LoopAuditEvent {
    SessionSpawn {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        provider: String,
        model: String,
        task_id: Option<String>,
        audit_tag: Option<String>,
    },
    SessionClose {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        reason: String,
    },
    HttpRequest {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        iteration: u32,
        provider: String,
        model: String,
        endpoint: String,
        body_sha256: String,
    },
    HttpResponse {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        iteration: u32,
        http_status: u16,
        stop_reason: String,
        usage: UsageSnapshot,
        body_sha256: String,
    },
    ToolCallRequested {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        iteration: u32,
        tool_name: String,
        tool_use_id: String,
        input_sha256: String,
    },
    ToolCallResult {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        iteration: u32,
        tool_name: String,
        tool_use_id: String,
        outcome: String,
        output_sha256: String,
        duration_ms: u128,
    },
    IterationBoundary {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        iteration: u32,
        continues: bool,
    },
    PolicyDenial {
        ts: DateTime<Utc>,
        run_id: String,
        session_id: String,
        iteration: u32,
        tool_name: String,
        reason: String,
    },
}

pub trait AuditSink: Send + Sync {
    fn emit(&self, event: &LoopAuditEvent);
    fn write_blob(&self, content: &[u8]) -> String;
}

pub struct NullSink;

impl AuditSink for NullSink {

        //    a `ToolCallRequested` event and emits its own `PolicyDenial`.
        //    When we see a `PolicyDenial`, we mirror it into a §7
        //    `tool.denied` envelope event so the higher-level trail records
        //    the policy outcome alongside the loop-level event.
        //
        // 2. A caller that bypasses the loop's own check could still emit a
        //    `ToolCallRequested` for a tool we shouldn't allow — we catch
        //    that here too and synthesize both a §7 `tool.denied` envelope
        //    event and a loop-level `PolicyDenial`.
        match event {
            LoopAuditEvent::PolicyDenial {
                tool_name, reason, ..
            } => {
                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
                *self.tripped.lock().expect("tripped mutex") = Some(EnforcementDecision::Denied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
                self.inner.emit(event);
            }
            LoopAuditEvent::ToolCallRequested { tool_name, .. }
                if !tool_allowed(tool_name, &self.allowlist) =>
            {
                let reason = format!("tool `{tool_name}` not in allowlist");
                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
                self.inner.emit(event);
                let denial = LoopAuditEvent::PolicyDenial {
                    ts: chrono::Utc::now(),
                    run_id: self.run_id.clone(),
                    session_id: self.session_id.clone(),
                    iteration: 0,
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                };
                self.inner.emit(&denial);
                *self.tripped.lock().expect("tripped mutex") = Some(EnforcementDecision::Denied {
                    tool_name: tool_name.clone(),
                    reason,
                });
            }
            _ => self.inner.emit(event),
        }
    }

    fn write_blob(&self, content: &[u8]) -> String {
        self.inner.write_blob(content)
    }
}

